import { BrowserRouter, Routes, Route } from "react-router-dom";
import Registration from "./registration";
import Mainweatherpage from "./mainweatherpage";
import Login from "./login";
import Convertmain from "./convertmain";
import Movies from "./movies";
import Crypto from "./crypto";
import News from "./news";
import Newsview from "./newsview";
import Verification from "./verification";
import Forgot from "./forgot";
import ChangePasswordPage from "./changepasswordpage";
import { useEffect, useState } from "react";

function App() {
  const [sessionres, changesessionres] = useState(null);

  async function checksession() {
    const response = await fetch("http://localhost:5000/checksession", {
      method: "GET",
      headers: { "Content-Type": "application/json" },
      credentials: "include"
    });

    const responsebool = await response.json();
    changesessionres(responsebool);
  }

  useEffect(() => {
    checksession();
  }, []);

  if (sessionres === null) {
    return <div>Loading...</div>;
  }

  return (
    <BrowserRouter>
      <Routes>
        <Route path="/" element={<Registration />} />
        <Route path="/login" element={<Login setSessionRes={changesessionres} />} />
          <Route path="/forgot" element={<Forgot/>} />
        <Route
          path="/weather"
          element={
            sessionres === false ? (
              <div className="notloggedin">
                <h1>You are not logged in</h1>
                <p>Please log in to view the weather</p>
              </div>
            ) : (
              <Mainweatherpage />
            )
          }
        />

        <Route
          path="/currencyconvert"
          element={
            sessionres === false ? (
              <div className="notloggedin">
                <h1>You are not logged in</h1>
                <p>Please log in to view the currency converter</p>
              </div>
            ) : (
              <Convertmain />
            )
          }
        />

        <Route
          path="/movies"
          element={
            sessionres === false ? (
              <div className="notloggedin">
                <h1>You are not logged in</h1>
                <p>Please log in to view the movies</p>
              </div>
            ) : (
              <Movies />
            )
          }
        />

        <Route
          path="/crypto"
          element={
            sessionres === false ? (
              <div className="notloggedin">
                <h1>You are not logged in</h1>
                <p>Please log in to view the crypto news</p>
              </div>
            ) : (
              <Crypto />
            )
          }
        />

        <Route
          path="/news"
          element={
            sessionres === false ? (
              <div className="notloggedin">
                <h1>You are not logged in</h1>
                <p>Please log in to view the news</p>
              </div>
            ) : (
              <News />
            )
          }
        />

        <Route
          path="/newsview"
          element={
            sessionres === false ? (
              <div className="notloggedin">
                <h1>You are not logged in</h1>
                <p>Please log in to view the news</p>
              </div>
            ) : (
              <Newsview />
            )
          }
        />

        <Route path="/verifiedemail" element={<Verification />} />
        <Route path="/resetpassword" element={<ChangePasswordPage />} />
      </Routes>
    </BrowserRouter>
  );
}

export default App;
